// // This is a 10-bit wide, 1-to-2 demultiplexer. Selects between two 10-bit outputs, A and B, based on the value of the 'sel' signal. When sel=0, the output 'out' takes the value of input A; when sel=1, the output takes the value of input B.
module top_module(	input [9:0]A, 
						input [9:0]B, 
						input sel,
						output [9:0]out
					);assign out = (sel) ? B : A;

endmodule
